    Assert.AreNotEqual(0m, cost);
}

[TestMethod]
public void CalculateShipping_JustAbove250_FreeShipping()
{
    var calc = new DiscountCalculator();
    Assert.AreEqual(0m, calc.CalculateShipping(250.01m, 5.0, true));
}

// Heavy item fee
[TestMethod]
public void CalculateShipping_HeavyItem_AddsHeavyFee()
{
    var calc = new DiscountCalculator();
    // 15kg: base = 5 + 15*0.50 = 12.50, + 15.00 heavy fee = 27.50
    var cost = calc.CalculateShipping(50m, 15.0, false);
    Assert.AreEqual(27.50m, cost);
}

[TestMethod]
public void CalculateShipping_Exactly10kg_NoHeavyFee()
{
    var calc = new DiscountCalculator();
    // 10kg: base = 5 + 10*0.50 = 10.00, no heavy fee
    var cost = calc.CalculateShipping(50m, 10.0, false);
    Assert.AreEqual(10.00m, cost);
}

// Express surcharge
[TestMethod]
public void CalculateShipping_Express_Adds50PercentSurcharge()
{
    var calc = new DiscountCalculator();
    // 2kg: base = 5 + 1.00 = 6.00, express = 6.00 * 1.50 = 9.00
    var cost = calc.CalculateShipping(50m, 2.0, true);
    Assert.AreEqual(9.00m, cost);
}

[TestMethod]
public void CalculateShipping_HeavyAndExpress_AppliesBothFees()
{
    var calc = new DiscountCalculator();
    // 15kg: base = 5 + 7.50 = 12.50, + 15.00 = 27.50, express = 27.50 * 1.50 = 41.25
    var cost = calc.CalculateShipping(50m, 15.0, true);
    Assert.AreEqual(41.25m, cost);
}

